import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { formatDistanceToNow } from 'date-fns';
import { toast } from 'react-toastify';
import './Feed.css';

const Feed = () => {
  const [posts, setPosts] = useState([]);
  const [newPost, setNewPost] = useState({ content: '', image: null, privacy: 'public' });
  const [loading, setLoading] = useState(true);
  const [commentInputs, setCommentInputs] = useState({});
  const [replyInputs, setReplyInputs] = useState({});
  const [editingPost, setEditingPost] = useState(null);
  const [editContent, setEditContent] = useState('');
  const [showDropdown, setShowDropdown] = useState(null);
  const [showReplyInput, setShowReplyInput] = useState({});
  const { user, logout } = useAuth();

  useEffect(() => {
    fetchPosts();
  }, []);

  const fetchPosts = async () => {
    try {
      const response = await axios.get('http://localhost:8000/api/posts/');
      setPosts(response.data.results || response.data);
    } catch (error) {
      console.error('Error fetching posts:', error);
      toast.error('Failed to load posts');
    } finally {
      setLoading(false);
    }
  };

  const handleCreatePost = async (e) => {
    e.preventDefault();
    if (!newPost.content.trim() && !newPost.image) {
      toast.warning('Please write something or add an image');
      return;
    }

    const formData = new FormData();
    formData.append('content', newPost.content);
    formData.append('privacy', newPost.privacy);
    if (newPost.image) {
      formData.append('image', newPost.image);
    }

    try {
      const response = await axios.post('http://localhost:8000/api/posts/', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setPosts([response.data, ...posts]);
      setNewPost({ content: '', image: null, privacy: 'public' });
      toast.success('Post created successfully!');
    } catch (error) {
      console.error('Error creating post:', error);
      toast.error('Failed to create post');
    }
  };

  const handleLike = async (postId) => {
    try {
      await axios.post(`http://localhost:8000/api/posts/${postId}/like/`);
      fetchPosts();
    } catch (error) {
      console.error('Error liking post:', error);
    }
  };

  const handleComment = async (postId) => {
    const content = commentInputs[postId];
    if (!content?.trim()) return;

    try {
      await axios.post(`http://localhost:8000/api/posts/${postId}/comment/`, { content });
      setCommentInputs({ ...commentInputs, [postId]: '' });
      fetchPosts();
      toast.success('Comment added!');
    } catch (error) {
      console.error('Error commenting:', error);
    }
  };

  const handleCommentLike = async (commentId) => {
    try {
      await axios.post(`http://localhost:8000/api/comments/${commentId}/like/`);
      fetchPosts();
    } catch (error) {
      console.error('Error liking comment:', error);
    }
  };

  const handleReply = async (commentId) => {
    const content = replyInputs[commentId];
    if (!content?.trim()) return;

    try {
      await axios.post(`http://localhost:8000/api/comments/${commentId}/reply/`, { content });
      setReplyInputs({ ...replyInputs, [commentId]: '' });
      setShowReplyInput({ ...showReplyInput, [commentId]: false });
      fetchPosts();
      toast.success('Reply added!');
    } catch (error) {
      console.error('Error replying:', error);
    }
  };

  const handleReplyLike = async (replyId) => {
    try {
      await axios.post(`http://localhost:8000/api/replies/${replyId}/like/`);
      fetchPosts();
    } catch (error) {
      console.error('Error liking reply:', error);
    }
  };

  const handleEditPost = async (postId) => {
    try {
      await axios.patch(`http://localhost:8000/api/posts/${postId}/`, { content: editContent });
      setEditingPost(null);
      setEditContent('');
      fetchPosts();
      toast.success('Post updated!');
    } catch (error) {
      console.error('Error editing post:', error);
      toast.error('Failed to update post');
    }
  };

  const handleDeletePost = async (postId) => {
    if (window.confirm('Are you sure you want to delete this post?')) {
      try {
        await axios.delete(`http://localhost:8000/api/posts/${postId}/`);
        fetchPosts();
        toast.success('Post deleted!');
      } catch (error) {
        console.error('Error deleting post:', error);
        toast.error('Failed to delete post');
      }
    }
  };

  const getInitials = (firstName, lastName) => {
    return `${firstName?.[0] || ''}${lastName?.[0] || ''}`.toUpperCase();
  };

  if (loading) {
    return (
      <div className="_layout_main_wrapper" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <div>Loading...</div>
      </div>
    );
  }

  return (
    <div className="_layout _layout_main_wrapper">
      <div className="_main_layout">
        {/* Header */}
        <nav className="navbar navbar-expand-lg navbar-light _header_nav _padd_t10">
          <div className="container _custom_container">
            <div className="_logo_wrap">
              <a className="navbar-brand" href="#">
                <img src="/assets/images/logo.svg" alt="Logo" className="_nav_logo" style={{ maxWidth: '169px' }} />
              </a>
            </div>
            <button className="navbar-toggler bg-light" type="button" data-bs-toggle="collapse" data-bs-target="#navbarSupportedContent">
              <span className="navbar-toggler-icon"></span>
            </button>
            <div className="collapse navbar-collapse" id="navbarSupportedContent">
              <div className="_header_form ms-auto">
                <form className="_header_form_grp" onSubmit={(e) => e.preventDefault()}>
                  <svg className="_header_form_svg" xmlns="http://www.w3.org/2000/svg" width="17" height="17" fill="none" viewBox="0 0 17 17">
                    <circle cx="7" cy="7" r="6" stroke="#666" />
                    <path stroke="#666" strokeLinecap="round" d="M16 16l-3-3" />
                  </svg>
                  <input className="form-control me-2 _inpt1" type="search" placeholder="Search..." aria-label="Search" />
                </form>
              </div>
              <div className="_header_nav_profile">
                <div className="_header_nav_profile_image">
                  <div style={{ width: '32px', height: '32px', borderRadius: '50%', background: '#1890FF', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold' }}>
                    {getInitials(user?.first_name, user?.last_name)}
                  </div>
                </div>
                <div className="_header_nav_dropdown">
                  <p className="_header_nav_para" style={{ margin: 0 }}>{user?.first_name} {user?.last_name}</p>
                  <button onClick={logout} className="_header_nav_dropdown_btn" type="button" style={{ background: 'none', border: 'none' }}>
                    <svg xmlns="http://www.w3.org/2000/svg" width="10" height="6" fill="none" viewBox="0 0 10 6">
                      <path fill="#112032" d="M5 5l.354.354L5 5.707l-.354-.353L5 5zm4.354-3.646l-4 4-.708-.708 4-4 .708.708zm-4.708 4l-4-4 .708-.708 4 4-.708.708z" />
                    </svg>
                  </button>
                </div>
              </div>
            </div>
          </div>
        </nav>

        {/* Main Content */}
        <div className="container _custom_container">
          <div className="_layout_inner_wrap">
            <div className="row">
              {/* Left Sidebar */}
              <div className="col-xl-3 col-lg-3 d-none d-lg-block">
                <div className="_layout_left_sidebar_wrap">
                  <div className="_layout_left_sidebar_inner">
                    <div className="_left_inner_area_explore _padd_t24 _padd_b6 _padd_r24 _padd_l24 _b_radious6 _feed_inner_area">
                      <h4 className="_left_inner_area_explore_title _title5 _mar_b24">Explore</h4>
                      <ul className="_left_inner_area_explore_list">
                        <li className="_left_inner_area_explore_item">
                          <a href="#" className="_left_inner_area_explore_link">
                            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="none" viewBox="0 0 20 20">
                              <path fill="#666" d="M10 0c5.523 0 10 4.477 10 10s-4.477 10-10 10S0 15.523 0 10 4.477 0 10 0z" />
                            </svg>
                            Feed
                          </a>
                        </li>
                        <li className="_left_inner_area_explore_item">
                          <a href="#" className="_left_inner_area_explore_link">
                            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="none" viewBox="0 0 20 20">
                              <path fill="#666" d="M10 0c5.523 0 10 4.477 10 10s-4.477 10-10 10S0 15.523 0 10 4.477 0 10 0z" />
                            </svg>
                            Friends
                          </a>
                        </li>
                      </ul>
                    </div>
                  </div>
                </div>
              </div>

              {/* Middle Feed */}
              <div className="col-xl-6 col-lg-6 col-md-12 col-sm-12">
                <div className="_layout_middle_wrap">
                  <div className="_layout_middle_inner">
                    {/* Create Post Card */}
                    <div className="_feed_inner_text_area _b_radious6 _padd_b24 _padd_t24 _padd_r24 _padd_l24 _mar_b16" style={{ background: 'white' }}>
                      <div className="_feed_inner_text_area_box">
                        <div className="_feed_inner_text_area_box_image">
                          <div style={{ width: '40px', height: '40px', borderRadius: '50%', background: '#0ACF83', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold' }}>
                            {getInitials(user?.first_name, user?.last_name)}
                          </div>
                        </div>
                        <div className="form-floating _feed_inner_text_area_box_form" style={{ flex: 1, marginLeft: '12px' }}>
                          <textarea 
                            className="form-control _textarea" 
                            placeholder="Write something ..." 
                            value={newPost.content}
                            onChange={(e) => setNewPost({ ...newPost, content: e.target.value })}
                            style={{ minHeight: '80px', border: '1px solid #e0e0e0', borderRadius: '8px', padding: '12px' }}
                          />
                        </div>
                      </div>
                      <div className="_feed_inner_text_area_bottom" style={{ marginTop: '16px', paddingTop: '16px', borderTop: '1px solid #e0e0e0' }}>
                        <div className="_feed_inner_text_area_item" style={{ display: 'flex', gap: '16px' }}>
                          <label className="_feed_common" style={{ cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="none" viewBox="0 0 20 20">
                              <path fill="#666" d="M13.916 0c3.109 0 5.18 2.429 5.18 5.914v8.17c0 3.486-2.072 5.916-5.18 5.916H5.999C2.89 20 .827 17.572.827 14.085v-8.17C.827 2.43 2.897 0 6 0h7.917z" />
                            </svg>
                            <input type="file" accept="image/*" style={{ display: 'none' }} onChange={(e) => setNewPost({ ...newPost, image: e.target.files[0] })} />
                            Photo
                          </label>
                          <select value={newPost.privacy} onChange={(e) => setNewPost({ ...newPost, privacy: e.target.value })} style={{ border: '1px solid #ddd', borderRadius: '6px', padding: '4px 8px' }}>
                            <option value="public">🌍 Public</option>
                            <option value="private">🔒 Private</option>
                          </select>
                        </div>
                        <button onClick={handleCreatePost} className="_feed_inner_text_area_btn_link" style={{ background: '#1890FF', border: 'none', borderRadius: '6px', padding: '8px 24px', color: 'white', fontWeight: '500' }}>
                          Post
                        </button>
                      </div>
                    </div>

                    {/* Posts Feed */}
                    {posts.map((post) => (
                      <div key={post.id} className="_feed_inner_timeline_post_area _b_radious6 _padd_b24 _padd_t24 _mar_b16" style={{ background: 'white', marginBottom: '16px' }}>
                        <div className="_feed_inner_timeline_content _padd_r24 _padd_l24">
                          {/* Post Header */}
                          <div className="_feed_inner_timeline_post_top" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                            <div className="_feed_inner_timeline_post_box" style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                              <div style={{ width: '44px', height: '44px', borderRadius: '50%', background: '#1890FF', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold' }}>
                                {getInitials(post.author?.first_name, post.author?.last_name)}
                              </div>
                              <div>
                                <h4 className="_feed_inner_timeline_post_box_title" style={{ margin: 0, fontSize: '16px', fontWeight: '600' }}>{post.author?.first_name} {post.author?.last_name}</h4>
                                <p className="_feed_inner_timeline_post_box_para" style={{ margin: 0, fontSize: '12px', color: '#666' }}>
                                  {formatDistanceToNow(new Date(post.created_at))} ago • 
                                  <span style={{ marginLeft: '4px' }}>{post.privacy === 'public' ? '🌍 Public' : '🔒 Private'}</span>
                                </p>
                              </div>
                            </div>
                            {post.author?.id === user?.id && (
                              <div className="_feed_inner_timeline_post_box_dropdown" style={{ position: 'relative' }}>
                                <button onClick={() => setShowDropdown(showDropdown === post.id ? null : post.id)} className="_feed_timeline_post_dropdown_link" style={{ background: 'none', border: 'none' }}>
                                  <svg xmlns="http://www.w3.org/2000/svg" width="4" height="17" fill="none" viewBox="0 0 4 17">
                                    <circle cx="2" cy="2" r="2" fill="#C4C4C4" />
                                    <circle cx="2" cy="8" r="2" fill="#C4C4C4" />
                                    <circle cx="2" cy="15" r="2" fill="#C4C4C4" />
                                  </svg>
                                </button>
                                {showDropdown === post.id && (
                                  <div style={{ position: 'absolute', right: 0, top: '100%', background: 'white', boxShadow: '0 2px 8px rgba(0,0,0,0.15)', borderRadius: '8px', padding: '8px 0', minWidth: '150px', zIndex: 10 }}>
                                    <button onClick={() => { setEditingPost(post.id); setEditContent(post.content); setShowDropdown(null); }} style={{ display: 'block', width: '100%', padding: '8px 16px', border: 'none', background: 'none', textAlign: 'left', cursor: 'pointer' }}>
                                      ✏️ Edit
                                    </button>
                                    <button onClick={() => handleDeletePost(post.id)} style={{ display: 'block', width: '100%', padding: '8px 16px', border: 'none', background: 'none', textAlign: 'left', cursor: 'pointer', color: '#dc3545' }}>
                                      🗑️ Delete
                                    </button>
                                  </div>
                                )}
                              </div>
                            )}
                          </div>

                          {/* Post Content */}
                          {editingPost === post.id ? (
                            <div style={{ marginBottom: '16px' }}>
                              <textarea value={editContent} onChange={(e) => setEditContent(e.target.value)} className="form-control" style={{ width: '100%', padding: '12px', border: '1px solid #ddd', borderRadius: '8px', marginBottom: '8px' }} />
                              <button onClick={() => handleEditPost(post.id)} style={{ background: '#1890FF', border: 'none', borderRadius: '6px', padding: '6px 16px', color: 'white', marginRight: '8px' }}>Save</button>
                              <button onClick={() => setEditingPost(null)} style={{ background: '#666', border: 'none', borderRadius: '6px', padding: '6px 16px', color: 'white' }}>Cancel</button>
                            </div>
                          ) : (
                            <p className="_feed_inner_timeline_post_title" style={{ marginBottom: '16px', fontSize: '14px', lineHeight: '1.5' }}>{post.content}</p>
                          )}

                          {/* Post Image */}
                          {post.image && (
                            <div className="_feed_inner_timeline_image" style={{ marginBottom: '16px' }}>
                              <img src={`http://localhost:8000${post.image}`} alt="Post" style={{ width: '100%', borderRadius: '8px' }} />
                            </div>
                          )}

                          {/* Stats */}
                          <div className="_feed_inner_timeline_total_reacts" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '12px 0', borderTop: '1px solid #e0e0e0', borderBottom: '1px solid #e0e0e0', marginBottom: '12px' }}>
                            <div className="_feed_inner_timeline_total_reacts_image" style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                              <span>❤️</span>
                              <span>{post.likes_count} likes</span>
                            </div>
                            <div>
                              <span>{post.comments_count} comments</span>
                            </div>
                          </div>

                          {/* Action Buttons */}
                          <div className="_feed_inner_timeline_reaction" style={{ display: 'flex', gap: '16px', marginBottom: '16px' }}>
                            <button onClick={() => handleLike(post.id)} className="_feed_reaction" style={{ flex: 1, padding: '8px', border: 'none', background: post.user_has_liked ? '#e8f4ff' : 'transparent', borderRadius: '6px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                              {post.user_has_liked ? '❤️' : '🤍'} Like
                            </button>
                          </div>

                          {/* Comments Section */}
                          <div className="_timline_comment_main">
                            {post.comments?.slice(0, 3).map((comment) => (
                              <div key={comment.id} className="_comment_main" style={{ display: 'flex', gap: '12px', marginBottom: '16px' }}>
                                <div className="_comment_image">
                                  <div style={{ width: '32px', height: '32px', borderRadius: '50%', background: '#FFCC4D', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '12px', fontWeight: 'bold' }}>
                                    {getInitials(comment.author?.first_name, comment.author?.last_name)}
                                  </div>
                                </div>
                                <div className="_comment_area" style={{ flex: 1 }}>
                                  <div className="_comment_details" style={{ background: '#F0F2F5', padding: '12px', borderRadius: '12px' }}>
                                    <div className="_comment_name">
                                      <h4 className="_comment_name_title" style={{ margin: 0, fontSize: '14px', fontWeight: '600' }}>{comment.author?.first_name} {comment.author?.last_name}</h4>
                                    </div>
                                    <div className="_comment_status">
                                      <p className="_comment_status_text" style={{ margin: '4px 0', fontSize: '13px' }}>{comment.content}</p>
                                    </div>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginTop: '8px' }}>
                                      <button onClick={() => handleCommentLike(comment.id)} style={{ background: 'none', border: 'none', fontSize: '12px', cursor: 'pointer' }}>
                                        {comment.user_has_liked ? '❤️' : '🤍'} {comment.likes_count}
                                      </button>
                                      <button onClick={() => setShowReplyInput({ ...showReplyInput, [comment.id]: !showReplyInput[comment.id] })} style={{ background: 'none', border: 'none', fontSize: '12px', cursor: 'pointer' }}>
                                        💬 Reply
                                      </button>
                                      <span style={{ fontSize: '11px', color: '#666' }}>{formatDistanceToNow(new Date(comment.created_at))} ago</span>
                                    </div>
                                  </div>

                                  {/* Replies */}
                                  {comment.replies?.map((reply) => (
                                    <div key={reply.id} style={{ display: 'flex', gap: '12px', marginTop: '12px', marginLeft: '40px' }}>
                                      <div style={{ width: '28px', height: '28px', borderRadius: '50%', background: '#0ACF83', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '10px', fontWeight: 'bold', color: 'white' }}>
                                        {getInitials(reply.author?.first_name, reply.author?.last_name)}
                                      </div>
                                      <div style={{ flex: 1, background: '#F8F9FA', padding: '10px', borderRadius: '10px' }}>
                                        <strong style={{ fontSize: '12px' }}>{reply.author?.first_name} {reply.author?.last_name}</strong>
                                        <p style={{ margin: '4px 0', fontSize: '12px' }}>{reply.content}</p>
                                        <div style={{ display: 'flex', gap: '12px', marginTop: '4px' }}>
                                          <button onClick={() => handleReplyLike(reply.id)} style={{ background: 'none', border: 'none', fontSize: '11px', cursor: 'pointer' }}>
                                            {reply.user_has_liked ? '❤️' : '🤍'} {reply.likes_count}
                                          </button>
                                          <span style={{ fontSize: '10px', color: '#666' }}>{formatDistanceToNow(new Date(reply.created_at))} ago</span>
                                        </div>
                                      </div>
                                    </div>
                                  ))}

                                  {/* Reply Input */}
                                  {showReplyInput[comment.id] && (
                                    <div style={{ display: 'flex', gap: '8px', marginTop: '12px', marginLeft: '40px' }}>
                                      <input type="text" placeholder="Write a reply..." className="form-control" style={{ flex: 1, padding: '8px', border: '1px solid #ddd', borderRadius: '6px' }} value={replyInputs[comment.id] || ''} onChange={(e) => setReplyInputs({ ...replyInputs, [comment.id]: e.target.value })} />
                                      <button onClick={() => handleReply(comment.id)} style={{ background: '#1890FF', border: 'none', borderRadius: '6px', padding: '8px 16px', color: 'white' }}>Reply</button>
                                    </div>
                                  )}
                                </div>
                              </div>
                            ))}

                            {/* Add Comment Input */}
                            <div className="_feed_inner_comment_box" style={{ marginTop: '16px' }}>
                              <div style={{ display: 'flex', gap: '12px', alignItems: 'flex-start' }}>
                                <div style={{ width: '32px', height: '32px', borderRadius: '50%', background: '#1890FF', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontSize: '12px', fontWeight: 'bold' }}>
                                  {getInitials(user?.first_name, user?.last_name)}
                                </div>
                                <div style={{ flex: 1 }}>
                                  <textarea 
                                    className="form-control _comment_textarea" 
                                    placeholder="Write a comment..." 
                                    value={commentInputs[post.id] || ''}
                                    onChange={(e) => setCommentInputs({ ...commentInputs, [post.id]: e.target.value })}
                                    style={{ width: '100%', padding: '10px', border: '1px solid #ddd', borderRadius: '8px', resize: 'none' }}
                                  />
                                  <button onClick={() => handleComment(post.id)} style={{ marginTop: '8px', background: '#1890FF', border: 'none', borderRadius: '6px', padding: '6px 20px', color: 'white' }}>
                                    Comment
                                  </button>
                                </div>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* Right Sidebar */}
              <div className="col-xl-3 col-lg-3 d-none d-lg-block">
                <div className="_layout_right_sidebar_wrap">
                  <div className="_layout_right_sidebar_inner">
                    <div className="_right_inner_area_info _padd_t24 _padd_b24 _padd_r24 _padd_l24 _b_radious6 _feed_inner_area" style={{ background: 'white' }}>
                      <h4 className="_title5" style={{ marginBottom: '16px' }}>Suggested</h4>
                      <div className="_right_inner_area_info_ppl">
                        <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '16px' }}>
                          <div style={{ width: '48px', height: '48px', borderRadius: '50%', background: '#667eea', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white' }}>JD</div>
                          <div>
                            <h4 style={{ margin: 0, fontSize: '14px', fontWeight: '600' }}>John Doe</h4>
                            <p style={{ margin: 0, fontSize: '12px', color: '#666' }}>Software Engineer</p>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Feed;
